// ==UserScript==
// @name         Telefe Clean Player UI Lite
// @namespace    telefe.clean.min.ui
// @version      1.0.0
// @description  UI minimalista para Telefe Vivo
// @match        https://www.mitelefe.com/vivo/*
// @match        https://www.mitelefe.com/*
// @grant        none
// @run-at       document-end
// ==/UserScript==

(function(){'use strict';

function waitForPlayer(){
const iframe=document.querySelector('#player-container iframe');
if(!iframe)return setTimeout(waitForPlayer,500);
buildUI();
}

function buildUI(){
const main=document.querySelector('main');
if(!main)return;

document.querySelectorAll('header,footer,.topics-menu,.ad-slot-billboard')
.forEach(el=>el.remove());

const wrapper=document.createElement('div');
wrapper.style.cssText='display:flex;flex-direction:column;align-items:center;justify-content:center;padding:20px;gap:15px;background:#111;color:white;';

const header=document.createElement('div');
header.style.cssText='display:flex;align-items:center;gap:10px;font-size:22px;font-weight:bold;letter-spacing:1px;';

const logo=document.createElement('img');
logo.src='https://www.mitelefe.com/media/cache/logo/logo-telefe-blanco-69286e9c2c776.png';
logo.style.height='40px';

const title=document.createElement('span');
title.textContent='| Telefe en Vivo';

header.appendChild(logo);
header.appendChild(title);

const player=document.querySelector('.player');
if(player){player.style.width='100%';player.style.maxWidth='900px';}

wrapper.appendChild(header);
if(player)wrapper.appendChild(player);

main.innerHTML='';
main.appendChild(wrapper);
}

waitForPlayer();

})();
